class Solution {
public:
    string licenseKeyFormatting(string s, int k) {
        string res;
        int n = s.size();
        int count = 0;
        for (int i = n - 1; i >= 0; --i) {
            if (s[i] != '-') {
                if (count == k) {
                    res = '-' + res;
                    count = 0;
                }
                res = toupper(s[i]) + res;
                count++;
            }
        }
        return res;
    }
};
```

efficiency: HIGH
